oxy_webhelp_navlinks = {"manage_protection_okta_idp-d27243e45895":{"topics":[{"title":"Creating SLA Domain for Okta tenants","shortdesc":"<p class=\"shortdesc\">Create a custom SLA Domain to define and apply customized data protection and         management policies for your Okta tenants.<\/p>","href":"okta\/creating_sla_domain_okta.html","attributes":{"data-id":"creating_sla_domain_okta"},"menu":{"hasChildren":false},"tocID":"creating_sla_domain_okta-d27243e45906","topics":[]},{"title":"Assigning protection to Okta tenants","shortdesc":"<p class=\"shortdesc\">Assign an SLA Domain to an Okta tenant to apply automated snapshot management         policies, ensuring data protection aligns with organizational requirements.<\/p>","href":"okta\/assigning_protection_okta_tenants.html","attributes":{"data-id":"assigning_protection_okta_tenants"},"menu":{"hasChildren":false},"tocID":"assigning_protection_okta_tenants-d27243e45917","topics":[]},{"title":"Taking on-demand snapshots of Okta tenants","shortdesc":"<p class=\"shortdesc\">As an <span class=\"ph\">RSC<\/span> user with the required privileges, you can manually         initiate an immediate, on-demand snapshot of an Okta tenant. You can take on-demand         snapshots in addition to your regularly scheduled backups.<\/p>","href":"okta\/taking_ods_okta_tenants.html","attributes":{"data-id":"taking_ods_okta_tenants"},"menu":{"hasChildren":false},"tocID":"taking_ods_okta_tenants-d27243e45928","topics":[]}]}};